'use server';

import { updateTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
};

const posts: Post[] = [
  { id: 1, title: 'First post' },
  { id: 2, title: 'Second post' }
];

export async function getPosts(): Promise<Post[]> {
  return posts;
}

export async function createPost(formData: FormData): Promise<void> {
  const title = formData.get('title');

  if (typeof title !== 'string' || title.trim().length === 0) {
    throw new Error('Title is required');
  }

  posts.unshift({
    id: Date.now(),
    title: title.trim()
  });

  // Use updateTag, not revalidateTag, so the next request blocks for fresh data
  // instead of serving stale-while-revalidate cached content.
  updateTag('posts');
}

import { createPost, getPosts } from './actions';

async function PostsList() {
  const posts = await fetch('https://example.com/api/posts', {
    next: { tags: ['posts'] }
  })
    .then(async (response) => {
      if (response.ok) {
        return (await response.json()) as Array<{ id: number; title: string }>;
      }

      return getPosts();
    })
    .catch(() => getPosts());

  return (
    <ul>
      {posts.map((post) => (
        <li key={post.id}>{post.title}</li>
      ))}
    </ul>
  );
}

export default function Home() {
  return (
    <main>
      <h1>Posts</h1>
      <form action={createPost}>
        <input name="title" type="text" placeholder="New post title" />
        <button type="submit">Create post</button>
      </form>
      <PostsList />
    </main>
  );
}

